// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract FileStorage {

    struct File {
        string cid;
        string fileName;
        address owner;
        uint256 uploadTime;
    }

    File[] public files;

    event FileUploaded(
        string cid,
        string fileName,
        address owner,
        uint256 uploadTime
    );

    function uploadFile(string memory _cid, string memory _fileName) public {

        files.push(
            File({
                cid: _cid,
                fileName: _fileName,
                owner: msg.sender,
                uploadTime: block.timestamp
            })
        );

        emit FileUploaded(
            _cid,
            _fileName,
            msg.sender,
            block.timestamp
        );
    }

    function getFile(uint index)
        public
        view
        returns (
            string memory,
            string memory,
            address,
            uint256
        )
    {
        File memory file = files[index];

        return (
            file.cid,
            file.fileName,
            file.owner,
            file.uploadTime
        );
    }

    function getFileCount() public view returns(uint){
        return files.length;
    }
}
